output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(COUNT(?richmond_year) AS ?count) WHERE {
  {
    SELECT(MIN(?collingwood_year) AS ?collingwood_year) WHERE {
      wd:Q249679 wdt:P1936 ?season .
      ?season wdt:P118 wd:Q521525 .
      ?season wdt:P585 ?collingwood_year .
    }
  }
  wd:Q2521385 wdt:P1936 ?richmond_season .
  ?richmond_season wdt:P118 wd:Q521525 .
  ?richmond_season wdt:P585 ?richmond_year .
  FILTER(?richmond_year > ?collingwood_year)
}

